namespace BogDb.Core.Common;

/// <summary>
/// Manages nullability flags for columnar data batches.
/// Represents a bit-packed array of ulongs where 1 indicates null.
/// </summary>
public class NullMask
{
    public const ulong NO_NULL_ENTRY = 0;
    public const ulong ALL_NULL_ENTRY = ulong.MaxValue;
    public const int NUM_BITS_PER_NULL_ENTRY_LOG2 = 6;
    public const ulong NUM_BITS_PER_NULL_ENTRY = 1UL << NUM_BITS_PER_NULL_ENTRY_LOG2; // 64

    private readonly ulong[] _buffer;
    private readonly Memory<ulong> _data;
    private bool _mayContainNulls;

    public bool MayContainNulls => _mayContainNulls;
    
    public ReadOnlyMemory<ulong> Data => _data;

    public NullMask(ulong capacity)
    {
        _mayContainNulls = false;
        ulong numNullEntries = (capacity + NUM_BITS_PER_NULL_ENTRY - 1) / NUM_BITS_PER_NULL_ENTRY;
        _buffer = new ulong[numNullEntries];
        _data = new Memory<ulong>(_buffer);
    }

    public NullMask(ulong[] existingData, bool mayContainNulls)
    {
        _buffer = existingData;
        _data = new Memory<ulong>(_buffer);
        _mayContainNulls = mayContainNulls;
    }

    public void SetAllNonNull()
    {
        if (!_mayContainNulls) return;
        _data.Span.Fill(NO_NULL_ENTRY);
        _mayContainNulls = false;
    }

    public void SetAllNull()
    {
        _data.Span.Fill(ALL_NULL_ENTRY);
        _mayContainNulls = true;
    }

    public bool HasNoNullsGuarantee() => !_mayContainNulls;

    public void SetNull(uint pos, bool isNull)
    {
        var (entryPos, bitPosInEntry) = GetNullEntryAndBitPos(pos);
        var span = _data.Span;

        if (isNull)
        {
            span[(int)entryPos] |= (1UL << (int)bitPosInEntry);
            _mayContainNulls = true;
        }
        else
        {
            span[(int)entryPos] &= ~(1UL << (int)bitPosInEntry);
        }
    }

    public bool IsNull(uint pos)
    {
        if (!_mayContainNulls) return false;
        var (entryPos, bitPosInEntry) = GetNullEntryAndBitPos(pos);
        return (_data.Span[(int)entryPos] & (1UL << (int)bitPosInEntry)) != 0;
    }

    private static (ulong EntryPos, ulong BitPosInEntry) GetNullEntryAndBitPos(ulong pos)
    {
        ulong nullEntryPos = pos >> NUM_BITS_PER_NULL_ENTRY_LOG2;
        ulong bitPosInEntry = pos - (nullEntryPos << NUM_BITS_PER_NULL_ENTRY_LOG2);
        return (nullEntryPos, bitPosInEntry);
    }

    public static ulong GetNumNullEntries(ulong numNullBits)
    {
        var quotient = numNullBits >> NUM_BITS_PER_NULL_ENTRY_LOG2;
        var remainder = numNullBits - (quotient << NUM_BITS_PER_NULL_ENTRY_LOG2);
        return quotient + (remainder == 0 ? 0UL : 1UL);
    }
}
